import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.ZhLefgN8.js";const _=JSON.parse('{"title":"持仓成本与盈亏计算","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/cost-basis-and-pnl.md","filePath":"zh-CN/portfolio-and-statements/cost-basis-and-pnl.md"}'),s={name:"portfolio-and-statements/cost-basis-and-pnl.md"};function n(p,a,i,l,d,c){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="持仓成本与盈亏计算" tabindex="-1">持仓成本与盈亏计算 <a class="header-anchor" href="#持仓成本与盈亏计算" aria-label="Permalink to &quot;持仓成本与盈亏计算&quot;">​</a></h1><p>长桥支持两种成本价计算方式：摊薄成本和平均开仓成本。</p><h2 id="摊薄成本" tabindex="-1">摊薄成本 <a class="header-anchor" href="#摊薄成本" aria-label="Permalink to &quot;摊薄成本&quot;">​</a></h2><p>摊薄成本代表您在开仓至平仓该段持有期内的保本价格。持有仓位期间，每次加仓或减仓都可能摊高或摊低该成本价。计算包含持有期内每次交易的盈亏（不含佣金及费用），同时考虑买入、卖出及企业行动现金分红的变化。</p><p>计算公式：<br> 多头：摊薄成本 = （持有期买入总金额 - 持有期卖出总金额 - 持有期的现金分红）/ 当前持有数量<br> 空头：摊薄成本 = （持有期卖出总金额 - 持有期买入总金额 - 持有期的现金分红）/ 当前持有数量</p><p>更新逻辑：买卖后实时更新。</p><h2 id="平均开仓成本" tabindex="-1">平均开仓成本 <a class="header-anchor" href="#平均开仓成本" aria-label="Permalink to &quot;平均开仓成本&quot;">​</a></h2><p>平均开仓成本只考虑加仓情况（不含佣金及费用），不考虑减仓。已减仓的部分将转为已实现盈亏。</p><p>计算公式：平均开仓成本 = （开仓前平均成本 × 开仓前数量 + 本次开仓金额）/ 买入后持有数量</p><p>更新逻辑：仅开仓成功时更新（多头买入开仓、空头卖出开仓），平仓或减仓不更新。</p><h2 id="如何切换计算方式" tabindex="-1">如何切换计算方式 <a class="header-anchor" href="#如何切换计算方式" aria-label="Permalink to &quot;如何切换计算方式&quot;">​</a></h2><p>长桥 App &gt; 我的 &gt; 设置 &gt; 资产设置 &gt; 成本计算方式，选择摊薄成本或平均开仓成本。</p><h2 id="成本计算统一规则" tabindex="-1">成本计算统一规则 <a class="header-anchor" href="#成本计算统一规则" aria-label="Permalink to &quot;成本计算统一规则&quot;">​</a></h2><p>以下规则对两种计算方式均适用：</p><p>日内同一方向的交易（如日内做多清仓后再建仓），系统视为做 T，延续持有期数据计算成本。</p><p>日内不同方向的交易（如日内做空 - 平仓 - 做多），清仓后成本清空，再次建仓重新开始计算。</p><p>注意：发生公司行动或转股时，成本价和盈亏的计算可能不准确，但不会影响实际资产。</p>',17)])])}const m=t(s,[["render",n]]);export{_ as __pageData,m as default};
